#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int a[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &a[i]);
    }
    for (int q = 0; q < Q; q++) {
        int L, R;
        scanf("%d %d", &L, &R);
        int count = 0;
        for (int i = L; i < R; i++) {
            for (int j = i + 1; j < R; j++) {
                for (int k = j + 1; k < R; k++) {
                    if (a[L - 1] > a[i] && a[i] < a[j] && a[j] > a[k] && a[k] < a[R - 1]) {
                        count++;
                    }
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

