public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] a = new int[N];
        for (int i = 0; i < N; i++) {
            a[i] = sc.nextInt();
        }
        for (int q = 0; q < Q; q++) {
            int L = sc.nextInt();
            int R = sc.nextInt();
            int count = 0;
            for (int i = L; i < R; i++) {
                for (int j = i + 1; j < R; j++) {
                    for (int k = j + 1; k < R; k++) {
                        if (a[L - 1] > a[i] && a[i] < a[j] && a[j] > a[k] && a[k] < a[R - 1]) {
                            count++;
                        }
                    }
                }
            }
            System.out.println(count);
